class Solution {
    public int findTargetSumWays(int[] nums, int target) {
        return dfs(nums, 0, 0, target);
    }

    private int dfs(int[] nums, int index, int sum, int target) {
        if (index == nums.length) return sum == target ? 1 : 0;
        return dfs(nums, index + 1, sum + nums[index], target) + dfs(nums, index + 1, sum - nums[index], target);
    }
}

class Solution {
    private Map<String, Integer> memo = new HashMap<>();

    public int findTargetSumWays(int[] nums, int target) {
        return dfs(nums, 0, 0, target);
    }

    private int dfs(int[] nums, int index, int sum, int target) {
        if (index == nums.length) return sum == target ? 1 : 0;
        String key = index + "," + sum;
        if (memo.containsKey(key)) return memo.get(key);
        int ways = dfs(nums, index + 1, sum + nums[index], target) + dfs(nums, index + 1, sum - nums[index], target);
        memo.put(key, ways);
        return ways;
    }
}

class Solution {
    public int findTargetSumWays(int[] nums, int target) {
        int sum = 0;
        for (int num : nums) sum += num;
        if ((sum + target) % 2 != 0 || sum < Math.abs(target)) return 0;
        int T = (sum + target) / 2;
        int[] dp = new int[T + 1];
        dp[0] = 1;
        for (int num : nums) {
            for (int j = T; j >= num; j--) {
                dp[j] += dp[j - num];
            }
        }
        return dp[T];
    }
}
